static const wchar_t* GetVersionCheckUrl()
{
    int releaseType = (currentVersion / 100) % 10;
    if (releaseType == ALPHA || releaseType == BETA || releaseType == RC)
        return L"https://raw.githubusercontent.com/Agzes/AntiAFK-RBX/refs/heads/preview/version.preview";
    return L"https://raw.githubusercontent.com/Agzes/AntiAFK-RBX/refs/heads/main/version";
}

static const wchar_t* GetReleaseChannelName()
{
    int releaseType = (currentVersion / 100) % 10;
    if (releaseType == ALPHA || releaseType == BETA || releaseType == RC)
        return L"Preview";
    return L"Stable";
}

static void FormatVersionReadable(int version, wchar_t* out, size_t outLen)
{
    int major = version / 10000000;
    int minor = (version / 100000) % 100;
    int patch = (version / 1000) % 100;
    int type = (version / 100) % 10;
    int num = version % 100;

    if (type == ALPHA) {
        swprintf_s(out, outLen, L"v.%d.%d.%d-alpha%d", major, minor, patch, num);
    } else if (type == BETA) {
        swprintf_s(out, outLen, L"v.%d.%d.%d-beta%d", major, minor, patch, num);
    } else if (type == RC) {
        swprintf_s(out, outLen, L"v.%d.%d.%d-rc%d", major, minor, patch, num);
    } else {
        swprintf_s(out, outLen, L"v.%d.%d.%d", major, minor, patch);
    }
}

static const wchar_t* GetAnnouncementUrl()
{
    int releaseType = (currentVersion / 100) % 10;
    if (releaseType == ALPHA || releaseType == BETA || releaseType == RC)
        return L"https://raw.githubusercontent.com/Agzes/AntiAFK-RBX/refs/heads/preview/Announcement/announcement.preview.json";
    return L"https://raw.githubusercontent.com/Agzes/AntiAFK-RBX/refs/heads/main/Announcement/announcement.json";
}

static const wchar_t* GetAnnouncementLink()
{
    int releaseType = (currentVersion / 100) % 10;
    if (releaseType == ALPHA || releaseType == BETA || releaseType == RC)
        return L"https://agzes.github.io/go/to/antiafk-rbx/preview-notify";
    return L"https://agzes.github.io/go/to/antiafk-rbx/notify";
}


