std::map<HWND, RobloxInstanceSettings> g_instanceSettings;
std::vector<RobloxInstancePreset> g_instancePresets = {
    { L"Default", false, true, false, false, false, false, 180, false, false, false, false, 60, false, true, false, true },
    { L"All off", true, false, true, false, true, false, 180, true, false, true, false, 0, true, false, true, false },
    { L"All on", true, true, true, true, true, true, 180, true, true, true, true, 60, true, true, true, true }
};
std::mutex g_instanceSettingsMutex;
std::mutex g_instancePresetsMutex;

bool GetWindowInstanceSetting_AntiAfk(HWND hwnd) {
    std::lock_guard<std::mutex> lock(g_instanceSettingsMutex);
    auto it = g_instanceSettings.find(hwnd);
    if (it != g_instanceSettings.end() && it->second.overrideAntiAfk) {
        return it->second.enableAntiAfk;
    }
    return true;
}

bool GetWindowInstanceSetting_Mute(HWND hwnd, bool globalDefault) {
    std::lock_guard<std::mutex> lock(g_instanceSettingsMutex);
    auto it = g_instanceSettings.find(hwnd);
    if (it != g_instanceSettings.end() && it->second.overrideMute) {
        return it->second.enableMute;
    }
    return globalDefault;
}

bool GetWindowInstanceSetting_Opacity(HWND hwnd, bool globalDefault, int& outOpacity) {
    std::lock_guard<std::mutex> lock(g_instanceSettingsMutex);
    auto it = g_instanceSettings.find(hwnd);
    if (it != g_instanceSettings.end() && it->second.overrideOpacity) {
        outOpacity = it->second.opacityValue;
        return it->second.enableOpacity;
    }
    outOpacity = 180;
    return globalDefault;
}

bool GetWindowInstanceSetting_Hide(HWND hwnd, bool globalDefault) {
    std::lock_guard<std::mutex> lock(g_instanceSettingsMutex);
    auto it = g_instanceSettings.find(hwnd);
    if (it != g_instanceSettings.end() && it->second.overrideHide) {
        return it->second.enableHide;
    }
    return globalDefault;
}

extern std::atomic<int> g_fpsLimit;
bool GetWindowInstanceSetting_FpsLimit(HWND hwnd, bool globalDefault, int& outFps) {
    std::lock_guard<std::mutex> lock(g_instanceSettingsMutex);
    auto it = g_instanceSettings.find(hwnd);
    if (it != g_instanceSettings.end() && it->second.overrideFpsLimit) {
        outFps = it->second.fpsLimitValue;
        return it->second.enableFpsLimit;
    }
    outFps = g_fpsLimit;
    return globalDefault;
}

bool GetWindowInstanceSetting_Reconnect(HWND hwnd, bool globalDefault) {
    std::lock_guard<std::mutex> lock(g_instanceSettingsMutex);
    auto it = g_instanceSettings.find(hwnd);
    if (it != g_instanceSettings.end() && it->second.overrideReconnect) {
        return it->second.enableReconnect;
    }
    return globalDefault;
}

bool GetWindowInstanceSetting_Reset(HWND hwnd, bool globalDefault) {
    std::lock_guard<std::mutex> lock(g_instanceSettingsMutex);
    auto it = g_instanceSettings.find(hwnd);
    if (it != g_instanceSettings.end() && it->second.overrideReset) {
        return it->second.enableReset;
    }
    return globalDefault;
}

