void ApplyActionPreset(int preset) {
    g_actionPreset = preset;
    if (preset == 0) { // Default
        g_preActionDelay = 55;
        g_keyPressDelay = 25;
        g_postActionDelay = 55;
        g_actionRepeatCount = 3;
    } else if (preset == 1) { // Safe
        g_preActionDelay = 100;
        g_keyPressDelay = 50;
        g_postActionDelay = 100;
        g_actionRepeatCount = 5;
    } else if (preset == 2) { // Custom
        // current ui values
    }
}


