// Multi Instance
MutexCreateResult EnableMultiInstanceSupport()
{
    if (g_hMultiInstanceMutex)
    {
        if (IsMultiInstanceMutexValid())
            return MUTEX_CREATED;
        DisableMultiInstanceSupport();
    }
    g_multiInstanceMutexOwnedByOther = false;
    g_hMultiInstanceMutex = CreateMutex(NULL, FALSE, L"ROBLOX_singletonEvent");
    if (!g_hMultiInstanceMutex)
        return MUTEX_CREATE_FAILED;
    if (GetLastError() == ERROR_ALREADY_EXISTS)
    {
        DWORD waitResult = WaitForSingleObject(g_hMultiInstanceMutex, 0);
        if (waitResult != WAIT_OBJECT_0)
        {
            bool robloxRunning = !FindAllRobloxProcessIds().empty();
            if (robloxRunning)
                return MUTEX_CREATED;
            g_multiInstanceMutexOwnedByOther = true;
            return MUTEX_ALREADY_EXISTS;
        }
        return MUTEX_CREATED;
    }
    return MUTEX_CREATED;
}
bool IsMultiInstanceMutexValid()
{
    if (!g_hMultiInstanceMutex) return false;
    DWORD result = WaitForSingleObject(g_hMultiInstanceMutex, 0);
    if (result == WAIT_OBJECT_0 || result == WAIT_ABANDONED)
    {
        if (!g_multiInstanceMutexOwnedByOther)
        {
            ReleaseMutex(g_hMultiInstanceMutex);
        }
        return true;
    }
    if (result == WAIT_TIMEOUT)
        return true;
    return false;
}
void DisableMultiInstanceSupport()
{
    if (g_hMultiInstanceMutex)
    {
        if (!g_multiInstanceMutexOwnedByOther)
        {
            ReleaseMutex(g_hMultiInstanceMutex);
        }
        CloseHandle(g_hMultiInstanceMutex);
        g_hMultiInstanceMutex = NULL;
    }
    g_multiInstanceMutexOwnedByOther = false;
}
void ShowMutexBanner(const std::wstring& message, const std::wstring& description, bool isSuccess)
{
    g_mutexBannerMessage = message;
    g_mutexBannerDescription = description;
    g_mutexBannerIsSuccess = isSuccess;
    if (g_hMainUiWnd && IsWindow(g_hMainUiWnd))
        InvalidateRect(g_hMainUiWnd, NULL, FALSE);
    if (g_hwnd && IsWindow(g_hwnd))
        CreateTrayMenu(g_isAfkStarted.load());
}
void ClearMutexBanner()
{
    g_mutexBannerMessage.clear();
    g_mutexBannerDescription.clear();
    g_mutexBannerIsSuccess = false;
    if (g_hMainUiWnd && IsWindow(g_hMainUiWnd))
        InvalidateRect(g_hMainUiWnd, NULL, FALSE);
    if (g_hwnd && IsWindow(g_hwnd))
        CreateTrayMenu(g_isAfkStarted.load());
}
