// Auto Reconnect Check
void IncrementalMouseMove(int startX, int startY, int endX, int endY, int steps, int duration)
{
    int screenWidth = GetSystemMetrics(SM_CXSCREEN);
    int screenHeight = GetSystemMetrics(SM_CYSCREEN);
    const double PI = 3.14159265358979323846;

    for (int i = 1; i <= steps; ++i)
    {
        double progress = (double)i / steps;
        double factor = 0.5 * (1.0 - cos(progress * PI));

        int currentX = (int)(startX + (endX - startX) * factor);
        int currentY = (int)(startY + (endY - startY) * factor);

        long absoluteX = currentX * 65535 / screenWidth;
        long absoluteY = currentY * 65535 / screenHeight;

        mouse_event(MOUSEEVENTF_MOVE | MOUSEEVENTF_ABSOLUTE, absoluteX, absoluteY, 0, 0);

        if (steps > 1 && duration > 0) {
            Sleep(duration / steps);
        }
    }

}

static int RandomInt(int max) {
    thread_local unsigned int seed = static_cast<unsigned int>(GetTickCount64() ^ reinterpret_cast<uintptr_t>(&seed));
    seed = 1664525U * seed + 1013904223U;
    return static_cast<int>((seed >> 16) % static_cast<unsigned int>(max));
}

static bool KickDialogDetected(HWND hRobloxWnd)
{
    RECT rc;
    if (!GetClientRect(hRobloxWnd, &rc)) return false;
    int w = rc.right - rc.left;
    int h = rc.bottom - rc.top;
    if (w < 30 || h < 30) return false;

    const int kickWidth = 400;
    const int kickHeight = 250;
    int elemX = (w - kickWidth) / 2;
    int elemY = (h - kickHeight) / 2;
    POINT checkPoint = {
        (std::max)(0, (std::min)(w - 1, elemX + 10)),
        (std::max)(0, (std::min)(h - 1, elemY + 10))
    };

    ClientToScreen(hRobloxWnd, &checkPoint);

    HDC hdcScreen = GetDC(NULL);
    if (!hdcScreen) return false;
    COLORREF pixelColor = GetPixel(hdcScreen, checkPoint.x, checkPoint.y);
    ReleaseDC(NULL, hdcScreen);

    return pixelColor == RGB(57, 59, 61);
}

bool CheckForAutoReconnect(HWND hRobloxWnd)
{
    if (g_stopThread.load() || !g_isAfkStarted.load()) return false;
    if (!IsWindow(hRobloxWnd) || !IsWindowVisible(hRobloxWnd)) {
        return false;
    }

    BringWindowToTop(hRobloxWnd);
    SetForegroundWindow(hRobloxWnd);
    Sleep(250);

    RECT clientRect;
    if (!GetClientRect(hRobloxWnd, &clientRect)) {
        return false;
    }
    int windowWidth = clientRect.right - clientRect.left;
    int windowHeight = clientRect.bottom - clientRect.top;

    const int kickWidth = 400;
    const int kickHeight = 250;
    int elemX = (windowWidth - kickWidth) / 2;
    int elemY = (windowHeight - kickHeight) / 2;
    POINT checkPoint = { elemX + 10, elemY + 10 };

    ClientToScreen(hRobloxWnd, &checkPoint);

    HDC hdcScreen = GetDC(NULL);
    if (!hdcScreen) return false;
    COLORREF pixelColor = GetPixel(hdcScreen, checkPoint.x, checkPoint.y);
    ReleaseDC(NULL, hdcScreen);

    if (pixelColor != RGB(57, 59, 61)) {
        return false;
    }

    const int btnWidth = 161;
    const int btnHeight = 34;
    int btnRelX = kickWidth - btnWidth - 27;
    int btnRelY = kickHeight - btnHeight - 21;
    int clickX = elemX + btnRelX + RandomInt(btnWidth);
    int clickY = elemY + btnRelY + RandomInt(btnHeight);

    POINT clickPoint = { clickX, clickY };
    ClientToScreen(hRobloxWnd, &clickPoint);

    POINT oldCursorPos;
    GetCursorPos(&oldCursorPos);

    IncrementalMouseMove(oldCursorPos.x, oldCursorPos.y, clickPoint.x, clickPoint.y, 20, 80);

    Sleep(30 + RandomInt(20));

    mouse_event(MOUSEEVENTF_LEFTDOWN, 0, 0, 0, 0);
    Sleep(40 + RandomInt(30));
    mouse_event(MOUSEEVENTF_LEFTUP, 0, 0, 0, 0);

    SetCursorPos(oldCursorPos.x, oldCursorPos.y);

    return true;
}

bool CheckForAutoReconnectNoFocus(HWND hRobloxWnd)
{
    if (g_stopThread.load() || !g_isAfkStarted.load()) return false;
    if (!IsWindow(hRobloxWnd)) {
        return false;
    }

    RECT clientRect;
    if (!GetClientRect(hRobloxWnd, &clientRect)) {
        return false;
    }
    int windowWidth = clientRect.right - clientRect.left;
    int windowHeight = clientRect.bottom - clientRect.top;
    if (windowWidth < 30 || windowHeight < 30) return false;

    bool windowWasHidden = !IsWindowVisible(hRobloxWnd) || IsIconic(hRobloxWnd);

    if (windowWasHidden) {
        ShowWindow(hRobloxWnd, SW_RESTORE);
        Sleep(200);
    }

    if (!KickDialogDetected(hRobloxWnd)) {
        if (windowWasHidden) ShowWindow(hRobloxWnd, SW_HIDE);
        return false;
    }

    RECT rc2;
    if (!GetClientRect(hRobloxWnd, &rc2)) {
        if (windowWasHidden) ShowWindow(hRobloxWnd, SW_HIDE);
        return false;
    }
    int ww = rc2.right - rc2.left;
    int wh = rc2.bottom - rc2.top;

    const int kickWidth = 400;
    const int kickHeight = 250;
    int elemX = (ww - kickWidth) / 2;
    int elemY = (wh - kickHeight) / 2;
    const int btnWidth = 161;
    const int btnHeight = 34;
    int btnRelX = kickWidth - btnWidth - 27;
    int btnRelY = kickHeight - btnHeight - 21;
    int clickX = elemX + btnRelX + RandomInt(btnWidth);
    int clickY = elemY + btnRelY + RandomInt(btnHeight);

    POINT clickPoint = { clickX, clickY };
    ClientToScreen(hRobloxWnd, &clickPoint);

    POINT oldCursorPos;
    GetCursorPos(&oldCursorPos);

    IncrementalMouseMove(oldCursorPos.x, oldCursorPos.y, clickPoint.x, clickPoint.y, 20, 80);

    Sleep(30 + RandomInt(20));

    mouse_event(MOUSEEVENTF_LEFTDOWN, 0, 0, 0, 0);
    Sleep(40 + RandomInt(30));
    mouse_event(MOUSEEVENTF_LEFTUP, 0, 0, 0, 0);

    SetCursorPos(oldCursorPos.x, oldCursorPos.y);

    if (windowWasHidden) {
        ShowWindow(hRobloxWnd, SW_HIDE);
    }

    return true;
}

void PerformReconnectCheckOnAllWindows(bool useFocus = false)
{
    if (!g_autoReconnect.load()) return;
    auto wins = FindAllRobloxWindows(true);
    if (wins.empty()) return;
    bool reconnectTriggered = false;
    DWORD now = GetTickCount();
    for (HWND w : wins) {
        if (g_stopThread.load() || !g_isAfkStarted.load()) break;
        if (!IsWindow(w)) continue;
        if (!GetWindowInstanceSetting_Reconnect(w, g_autoReconnect.load())) continue;
        {
            std::lock_guard<std::mutex> lock(g_reconnectCooldownMutex);
            auto it = g_reconnectCooldownMap.find(w);
            if (it != g_reconnectCooldownMap.end() && (now - it->second) < 30000) continue;
        }
        bool triggered = useFocus ? CheckForAutoReconnect(w) : CheckForAutoReconnectNoFocus(w);
        if (triggered) {
            g_autoReconnectsPerformed++;
            reconnectTriggered = true;
            std::lock_guard<std::mutex> lock(g_reconnectCooldownMutex);
            g_reconnectCooldownMap[w] = now;
        }
    }
    if (reconnectTriggered) {
        QueueDiscordWebhookEvent(DiscordWebhookEvent::AutoReconnect, L"Reconnect triggered (interval check).", false);
        QueueStatusBarOverlay(L"Auto-Reconnect triggered", 2000, wins.front());
    }
}

void ReconnectMonitorThread()
{
    g_reconnectMonitorRunning = true;
    while (!g_stopThread.load() && g_reconnectMonitorRunning.load()) {
        int intervalSec = g_reconnectCheckInterval.load();
        if (!g_autoReconnect.load() || !g_isAfkStarted.load()) {
            Sleep(1000);
            continue;
        }
        if (intervalSec <= 0) intervalSec = 60;
        {
            std::lock_guard<std::mutex> lock(g_reconnectCooldownMutex);
            DWORD now = GetTickCount();
            for (auto it = g_reconnectCooldownMap.begin(); it != g_reconnectCooldownMap.end(); ) {
                if ((now - it->second) > 60000) it = g_reconnectCooldownMap.erase(it);
                else ++it;
            }
        }
        for (int i = 0; i < intervalSec * 2 && !g_stopThread.load() && g_reconnectMonitorRunning.load(); ++i) {
            if (g_reconnectManualCheckRequest.exchange(false)) {
                PerformReconnectCheckOnAllWindows(true);
            }
            Sleep(500);
        }
        if (g_stopThread.load() || !g_reconnectMonitorRunning.load() || !g_isAfkStarted.load()) break;
        if (g_autoReconnect.load()) {
            PerformReconnectCheckOnAllWindows();
        }
    }
    g_reconnectMonitorRunning = false;
}

void StartReconnectMonitor()
{
    if (g_reconnectMonitorRunning.load()) return;
    if (g_reconnectMonitorThread.joinable()) {
        g_reconnectMonitorThread.join();
    }
    g_reconnectMonitorThread = std::thread(ReconnectMonitorThread);
}

void StopReconnectMonitor()
{
    g_reconnectMonitorRunning = false;
    if (g_reconnectMonitorThread.joinable()) {
        g_reconnectMonitorThread.join();
    }
    std::lock_guard<std::mutex> lock(g_reconnectCooldownMutex);
    g_reconnectCooldownMap.clear();
}
