{
    std::lock_guard<std::mutex> lock(g_discordWebhookMutex);
    return g_discordWebhookUrl;
}

void SetDiscordWebhookUrl(const std::wstring& value)
{
    std::lock_guard<std::mutex> lock(g_discordWebhookMutex);
    g_discordWebhookUrl = NormalizeDiscordWebhookUrl(value);
}

