    pData->gridBackIconRect = pData->iconButtonRect;
    pData->actionDelaysBackIconRect = pData->iconButtonRect;
    pData->fpsCapperSettingsBackIconRect = pData->iconButtonRect;
    pData->alphaInfoBackIconRect = pData->iconButtonRect;
