    COLORREF startHoverColor_normal = isStarted ? RGB(230, 40, 40) : RGB(20, 142, 224);
    COLORREF currentStartColor_normal = pData->isHoveringStart ? startHoverColor_normal : startColor_normal;
    COLORREF startColor_previous_normal = pData->previousAfkStartedState ? RGB(200, 30, 30) : RGB(0, 122, 204);
    COLORREF baseColor_normal = pData->isHoveringStart ? startHoverColor_normal : currentStartColor_normal;

    float stateProgress = pData->stateChangeProgress;
    BYTE r_state_normal = (BYTE)(GetRValue(startColor_previous_normal) * (1.0f - stateProgress) + GetRValue(baseColor_normal) * stateProgress);
    BYTE g_state_normal = (BYTE)(GetGValue(startColor_previous_normal) * (1.0f - stateProgress) + GetGValue(baseColor_normal) * stateProgress);
    BYTE b_state_normal = (BYTE)(GetBValue(startColor_previous_normal) * (1.0f - stateProgress) + GetBValue(baseColor_normal) * stateProgress);

    COLORREF errorColor = RGB(80, 80, 80);
    float progress = pData->errorAnimationProgress;
    BYTE r_normal = (BYTE)(r_state_normal * (1.0f - progress) + GetRValue(errorColor) * progress);
    BYTE g_normal = (BYTE)(g_state_normal * (1.0f - progress) + GetGValue(errorColor) * progress);
    BYTE b_normal = (BYTE)(b_state_normal * (1.0f - progress) + GetBValue(errorColor) * progress);

    float overlayAnim = max(max(max(max(gridAnim, actionDelaysAnim), fpsCapperSettingsAnim), alphaInfoAnim), timingsAnim);

    bool isContinueBtn = pData->alphaInfoAutoShown && alphaInfoAnim > 0.0f && alphaInfoAnim >= overlayAnim * 0.99f;
    COLORREF startColor_back = isContinueBtn ? RGB(0, 100, 180) : RGB(80, 80, 80);
    COLORREF startHoverColor_back = isContinueBtn ? RGB(0, 130, 210) : RGB(100, 100, 100);
    bool isOverlayOkHovered = pData->isHoveringGridOkButton || pData->isHoveringActionDelaysOkButton || pData->isHoveringFpsCapperSettingsOkButton || pData->isHoveringAlphaInfoOkButton || pData->isHoveringTimingsOkButton;
    COLORREF currentBackColor = isOverlayOkHovered ? startHoverColor_back : startColor_back;
    BYTE r_back = GetRValue(currentBackColor);
    BYTE g_back = GetGValue(currentBackColor);
    BYTE b_back = GetBValue(currentBackColor);

    BYTE r = (BYTE)(r_normal * (1.0f - overlayAnim) + r_back * overlayAnim);
    BYTE gr = (BYTE)(g_normal * (1.0f - overlayAnim) + g_back * overlayAnim);
    BYTE b = (BYTE)(b_normal * (1.0f - overlayAnim) + b_back * overlayAnim);

