        y += rowH + vGap;

        pData->rowRects.push_back({ 0, y, clientRect.right, y + rowH + vGap });
        pData->hotkeyToggleRect = { ctrlStartX, y, ctrlStartX + genCtrlW, y + rowH };
        int toggleX_rightEdge = clientRect.right - help_btn_size - 20;
