        MainUI_Paint_DrawDropdown(hdc, pData->intervalDropdownRect, pData->hFontText, L"Interval", buffer, pData->isHoveringInterval, true, L"\uE916", true, nullptr, 1, -1);

        const wchar_t* actionNames[] = { L"Space (Jump)", L"W/S", L"Zoom (I/O)" };
        MainUI_Paint_DrawDropdown(hdc, pData->actionDropdownRect, pData->hFontText, L"Action", actionNames[g_selectedAction.load()], pData->isHoveringAction, true, L"\uE7C9");
        MainUI_Paint_DrawCompactButton(hdc, pData->actionDelaysSettingsCompactRect, pData->hFontText, L"\uE713", pData->isHoveringActionDelaysSettingsCompact, L"\uE713", false);

        MainUI_Paint_DrawToggle(hdc, pData->multiInstanceToggleRect, pData->hFontText, L"Multi-Instance bypass", g_multiSupport.load(), pData->isHoveringMultiInstanceToggle, pData->multiInstanceAnim, true, L"\uE81E");

        MainUI_Paint_DrawCompactButton(hdc, pData->advancedMultiInstanceLinkRect, pData->hFontText, L"\uE713", pData->isHoveringAdvancedMultiInstanceLink, L"\uE713", false);

        if (pData->mutexStatusAnim > 0.01f) {
            bool mutexOk = IsMultiInstanceMutexValid();
            bool hasError = !g_mutexBannerMessage.empty() && !g_mutexBannerIsSuccess;
            bool ignored = g_mutexIgnored && !mutexOk;
            bool success = mutexOk && !hasError && !ignored;
            const wchar_t* statusIcon = (ignored || mutexOk) ? L"\uE73E" : L"\uE711";
            RECT statusRect = pData->mutexStatusRect;
            BYTE a = (BYTE)(pData->mutexStatusAnim * 255);
            bool hover = success ? false : pData->isHoveringMutexStatus;
            BYTE fillA = (BYTE)(pData->mutexStatusAnim * (hover ? 140 : 140));
            BYTE borderA = (BYTE)(pData->mutexStatusAnim * 180);
            Color fillColor(fillA, hover ? 80 : 55, hover ? 80 : 55, hover ? 80 : 55);
            Color borderColor(borderA, 56, 56, 56);
            REAL bw = (REAL)(statusRect.right - statusRect.left), bh = (REAL)(statusRect.bottom - statusRect.top);
            SolidBrush fillBrush(fillColor);
            Pen borderPen(borderColor, 1.0f);
            GraphicsPath path;
            REAL radius = 5.0f;
            path.AddArc((REAL)statusRect.left, (REAL)statusRect.top, radius * 2, radius * 2, 180, 90);
            path.AddLine((REAL)statusRect.left + radius, (REAL)statusRect.top, (REAL)statusRect.right - radius, (REAL)statusRect.top);
            path.AddArc((REAL)statusRect.right - radius * 2, (REAL)statusRect.top, radius * 2, radius * 2, 270, 90);
            path.AddLine((REAL)statusRect.right, (REAL)statusRect.top + radius, (REAL)statusRect.right, (REAL)statusRect.bottom - radius);
            path.AddArc((REAL)statusRect.right - radius * 2, (REAL)statusRect.bottom - radius * 2, radius * 2, radius * 2, 0, 90);
            path.AddLine((REAL)statusRect.right - radius, (REAL)statusRect.bottom, (REAL)statusRect.left + radius, (REAL)statusRect.bottom);
            path.AddArc((REAL)statusRect.left, (REAL)statusRect.bottom - radius * 2, radius * 2, radius * 2, 90, 90);
            path.AddLine((REAL)statusRect.left, (REAL)statusRect.bottom - radius, (REAL)statusRect.left, (REAL)statusRect.top + radius);
            path.CloseFigure();
            {
                SmoothingMode oldSmooth = g.GetSmoothingMode();
                PixelOffsetMode oldOffset = g.GetPixelOffsetMode();
                g.SetSmoothingMode(SmoothingModeAntiAlias);
                g.SetPixelOffsetMode(PixelOffsetModeHalf);
                g.FillPath(&fillBrush, &path);
                g.SetPixelOffsetMode(PixelOffsetModeNone);
                g.DrawPath(&borderPen, &path);
                g.SetPixelOffsetMode(oldOffset);
                g.SetSmoothingMode(oldSmooth);
            }
            HFONT iconFontH = CreateFontW(-MulDiv(9, GetDeviceCaps(hdc, LOGPIXELSY), 72), 0, 0, 0, FW_NORMAL, 0, 0, 0, DEFAULT_CHARSET, 0, 0, CLEARTYPE_QUALITY, 0, L"Segoe MDL2 Assets");
            Font iconFont(hdc, iconFontH);
            SolidBrush iconBrush(Color(a, 200, 200, 200));
            StringFormat sfIcon;
            sfIcon.SetAlignment(StringAlignmentCenter);
            sfIcon.SetLineAlignment(StringAlignmentCenter);
            RectF iconRect((REAL)statusRect.left + 1, (REAL)statusRect.top + 1.5f, bw, bh);
            g.DrawString(statusIcon, -1, &iconFont, iconRect, &sfIcon, &iconBrush);
            if (ignored) {
                g.DrawString(L"\uEA84", -1, &iconFont, iconRect, &sfIcon, &iconBrush);
            }
            DeleteObject(iconFontH);
        }
