        {
            int command = LOWORD(wParam);
            int newLimit = 15;
            switch (command) {
                case ID_FPS_CAP_3:   newLimit = 3; break;
                case ID_FPS_CAP_5:   newLimit = 5; break;
                case ID_FPS_CAP_7:   newLimit = 7; break;
                case ID_FPS_CAP_10:  newLimit = 10; break;
                case ID_FPS_CAP_15:  newLimit = 15; break;
            }

            int oldLimit = g_fpsLimit;
            g_fpsLastActiveLimit = newLimit;
            if (g_fpsLimit > 0) {
                g_fpsLimit = newLimit;
            }

            if (oldLimit != g_fpsLimit) {
                RestartFpsCapperForEffectiveLimit();
            }
            SaveSettings();
            CreateTrayMenu(g_isAfkStarted.load());
            if (g_hMainUiWnd && IsWindow(g_hMainUiWnd)) {
                InvalidateRect(g_hMainUiWnd, NULL, TRUE);
            }
            wchar_t msgBuf[128];
            swprintf_s(msgBuf, L"FPS Capper (CPU Limiter) configured to %d FPS", newLimit);
            ShowStatusBarOverlay(msgBuf, 1700, g_hMainUiWnd && IsWindow(g_hMainUiWnd) ? g_hMainUiWnd : hwnd);
            break;
        }
